import { createGlobalValueSetter } from 'Shared/store/createGlobalValueSetter';
import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';
import { ModalNameE } from 'Components/modal/ModalNameE';
import { ModalPropsT } from 'Components/modal/ModalPropsT';

const updateModals = createGlobalValueSetter(GlobalStoreFieldE.MODALS);

export const modalService = {
  open: <N extends ModalNameE>(
    modalName: N,
    ...args: ModalPropsT[N] extends void ? [] : [props: ModalPropsT[N]]
  ) => {
    updateModals(currentModals => {
      return [
        {
          deleted: false,
          name: modalName,
          props: args[0],
        },
        ...currentModals,
      ];
    });

    return modalName;
  },
  close: (modalName: ModalNameE) => {
    updateModals(modals => {
      return modals.filter(modal => modal.name !== modalName);
    });
  },
};

